import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit'
import { collection, query, getDocs } from 'firebase/firestore'
import { db } from '@/lib/firebase'

export interface Tour {
  id: string
  image: string
  title: string
  description: string
}

interface ToursState {
  tours: Tour[]
  loading: boolean
  error: string | null
}

const initialState: ToursState = {
  tours: [],
  loading: false,
  error: null
}

export const fetchTours = createAsyncThunk(
  'tours/fetchTours',
  async () => {
    const q = query(collection(db, "tours"))
    const querySnapshot = await getDocs(q)
    const toursData: Tour[] = []
    querySnapshot.forEach((doc) => {
      const data = doc.data()
      toursData.push({
        id: doc.id,
        image: data.image || "",
        title: data.title || "Untitled",
        description: data.description || "No description available",
      })
    })
    return toursData
  }
)

const toursSlice = createSlice({
  name: 'tours',
  initialState,
  reducers: {
    clearToursError: (state) => {
      state.error = null
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchTours.pending, (state) => {
        state.loading = true
        state.error = null
      })
      .addCase(fetchTours.fulfilled, (state, action: PayloadAction<Tour[]>) => {
        state.loading = false
        state.tours = action.payload
      })
      .addCase(fetchTours.rejected, (state, action) => {
        state.loading = false
        state.error = action.error.message || 'Failed to fetch tours'
      })
  }
})

export const { clearToursError } = toursSlice.actions
export default toursSlice.reducer