import { createSlice,createAsyncThunk,PayloadAction } from "@reduxjs/toolkit";
import { collection,query,getDocs } from "firebase/firestore";
import { db } from "@/lib/firebase";

export interface Attraction {
  id: string;
  title: string;
  name: string;
  description: string;
  image: string;
  location: string;
  duration: string;
  price: string;
  activity: string;
  age: string;
}
interface AttractionsState {
  attractions: Attraction[];
  loading: boolean;
  error: string | null;
}
const initialState: AttractionsState = {
  attractions: [],
  loading: false,
  error: null,
};

export const fetchAttractions = createAsyncThunk(
  'attractions/fetchAttractions',
  async () => {
    const q = query(collection(db, "attractions"));
    const querySnapshot = await getDocs(q);
    const attractionsData: Attraction[] = [];
    querySnapshot.forEach((doc) => {
      const data = doc.data();
      attractionsData.push({
        id: doc.id,
        name: data.name || "Untitled",
        title: data.title || "Untitled",
        description: data.description || "No description available",
        image: data.image || "",
        location: data.location || "Unknown",
        duration: data.duration || "N/A",
        price: data.price || "N/A",
        activity: data.activity || "N/A",
        age: data.age || "All ages",
      });
    });
    return attractionsData;
  }
);

const attractionsSlice = createSlice({
  name: 'attractions',
  initialState,
  reducers: {
    clearAttractionsError: (state) => {
      state.error = null;
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchAttractions.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchAttractions.fulfilled, (state, action: PayloadAction<Attraction[]>) => {
        state.loading = false;
        state.attractions = action.payload;
      })
      .addCase(fetchAttractions.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message || "Failed to fetch attractions";
      });
  }
});

export const { clearAttractionsError } = attractionsSlice.actions;
export default attractionsSlice.reducer;